import { client } from "@/trigger";
import { schemaTask, ai } from "@trigger.dev/sdk";

// Define the refine-text task that takes a string and improves it
// This task mocks text refinement - in production you'd use a real LLM
const refineTask = schemaTask({
  id: "refine-text",
  schema: {
    input: {
      type: "object",
      properties: {
        text: {
          type: "string",
          description: "The text to be refined and improved",
        },
        iteration: {
          type: "number",
          description: "The current iteration number",
        },
      },
      required: ["text"],
    },
    output: {
      type: "object",
      properties: {
        refinedText: {
          type: "string",
          description: "The refined/improved text",
        },
        iteration: {
          type: "number",
          description: "The iteration number",
        },
        needsFurtherRefinement: {
          type: "boolean",
          description: "Whether the text needs further refinement",
        },
      },
      required: ["refinedText"],
    },
  },
  run: async ({ text, iteration = 1 }) => {
    // Mock text refinement logic
    // In production, you would call an LLM API here

    // Simulate refinement by adding iteration-specific improvements
    const improvements = [
      "First refinement: Improved clarity and structure.",
      "Second refinement: Enhanced vocabulary and flow.",
      "Third refinement: Polished tone and readability.",
    ];

    const improvementIndex = Math.min(iteration - 1, improvements.length - 1);
    const refinedText = `${text}\n\n[${improvements[improvementIndex]}]`;

    // Determine if further refinement is needed (mock logic)
    const needsFurtherRefinement = iteration < 2;

    return {
      refinedText,
      iteration,
      needsFurtherRefinement,
    };
  },
});

// Wrap the refine task using ai.tool
const refineTool = ai.tool(refineTask);

// Define the parent agent-loop task that uses the tool in a loop
// to refine a text at least twice
const agentLoopTask = schemaTask({
  id: "agent-loop",
  schema: {
    input: {
      type: "object",
      properties: {
        text: {
          type: "string",
          description: "The initial text to be refined",
        },
        maxIterations: {
          type: "number",
          description: "Maximum number of refinement iterations",
          default: 3,
        },
      },
      required: ["text"],
    },
    output: {
      type: "object",
      properties: {
        finalText: {
          type: "string",
          description: "The final refined text",
        },
        iterations: {
          type: "number",
          description: "Total number of iterations performed",
        },
        refinementHistory: {
          type: "array",
          items: {
            type: "string",
          },
          description: "History of refined texts at each iteration",
        },
      },
      required: ["finalText", "iterations", "refinementHistory"],
    },
  },
  run: async ({ text, maxIterations = 3 }) => {
    const refinementHistory: string[] = [];
    let currentText = text;
    let iteration = 0;

    // Refinement loop - refine at least twice (minimum 2 iterations)
    while (iteration < maxIterations) {
      iteration++;

      // Use the AI tool to refine the text
      const result = await refineTool.invoke({
        text: currentText,
        iteration,
      });

      // Update current text with refined version
      currentText = result.refinedText;
      refinementHistory.push(currentText);

      // Check if further refinement is needed
      if (!result.needsFurtherRefinement) {
        // Continue for at least 2 iterations as required
        if (iteration >= 2) {
          break;
        }
      }
    }

    return {
      finalText: currentText,
      iterations: iteration,
      refinementHistory,
    };
  },
});

// Register the tasks with the client
client.defineJob({
  id: "agent-loop-job",
  name: "AI Agent Refinement Loop",
  version: "1.0.0",
  trigger: cron.schedule({
    cron: "0 * * * *", // Run every hour (example trigger)
  }),
  run: async (_, { logger }) => {
    logger.log("Starting AI Agent Refinement Loop");

    // Example usage with a sample text
    const sampleText = "This is a sample text that needs refinement.";

    const result = await agentLoopTask.run({
      text: sampleText,
      maxIterations: 3,
    });

    logger.log(`Refinement completed after ${result.iterations} iterations`);
    logger.log(`Final text: ${result.finalText}`);

    return result;
  },
});

// Export the tasks for use in other files
